),
source_rows as (
  select
    m.*,
    c.document_id,
    c.chunk_id,
    c.content,
    c.embedding
  from manifest m
  join compass.document_chunks c
    on c.id = m.source_row_id
   and c.document_id = m.source_document_id
   and c.chunk_id = m.source_chunk_id
  where c.content is not null
    and c.embedding is not null
    and vector_dims(c.embedding) = 1024
),
inserted as (
  insert into compass.ollama_document_chunks (
    document_id,
    chunk_id,
    content,
    embedding,
    metadata,
    created_at,
    updated_at
  )
  select
    source_document_id as document_id,
    target_chunk_id as chunk_id,
    content,
    embedding,
    metadata_payload::jsonb,
    now() as created_at,
    now() as updated_at
  from source_rows s
  where not exists (
    select 1
    from compass.ollama_document_chunks o
    where o.chunk_id = s.target_chunk_id
  )
  on conflict do nothing
  returning chunk_id
)
select
  'rag3k_inserted_rows' as check_name,
  count(*)::text as value
from inserted;
